import { useEffect, useState } from 'react';

/**
 * Bump when topbar switches X-Company-Id — catalog list + ui-schema are tenant-scoped.
 */
export function useCatalogReloadOnCompanyChange(): number {
  const [key, setKey] = useState(0);

  useEffect(() => {
    const onChange = () => setKey(k => k + 1);
    window.addEventListener('linm:company:changed', onChange);
    return () => window.removeEventListener('linm:company:changed', onChange);
  }, []);

  return key;
}
